text:
{
  "formal_minutes": {
    "confirmed_decisions": [
      {
        "item": "공개 릴리스 목표일을 '금요일 15:00 KST'로 설정한다.",
        "condition": "스모크 테스트가 통과한 경우에 한함"
      },
      {
        "item": "packageName 불일치 발생 시, 스크립트 변경보다 먼저 패키지 설정(컨트랙트/설정 값)을 먼저 점검한다."
      },
      {
        "item": "패키지 설정이 실제로 잘못된 경우에만 스크립트를 재검토한다."
      },
      {
        "item": "Minjun: 금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과 공유."
      },
      {
        "item": "Doyun: 금요일 12:00 KST까지 action_items.md에 실패 분석(트리아지) 노트 작성."
      }
    ],
    "rejected_proposals": [
      {
        "item": "Hara의 'smoke-theme-pack.mjs에서 packageName 불일치 무시' 제안"
      },
      {
        "item": "수요일 공개 릴리스 타깃 설정"
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 공개 릴리스(내부 목표) 설정",
        "status": "내부 스트레치 목표로만 유지, 최종 공개 타깃이 아님"
      },
      {
        "item": "README 설치 단계 검토를 목요일까지 가능하면 진행",
        "status": "권고/희망 일정, 확정 과업 아님"
      }
    ],
    "risks": [
      {
        "item": "tarball 경로가 잘못되면 릴리스가 지연될 수 있음",
        "owner_assigned": false
      },
      {
        "item": "README 설치 단계가 오래되면 릴리스 노트가 사용자에게 오해를 줄 수 있음",
        "owner_assigned": false
      }
    ],
    "open_questions": [
      {
        "item": "최종 릴리스 승인 권한은 누구에게 있는가?"
      },
      {
        "item": "릴리스 노트에 내부 수요일 스트레치 목표(수요일 목표치)를 언급할지 여부?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트 재실행 및 결과 공유",
      "due": "2026-05-15 10:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Doyun",
      "task": "실패 트리아지 노트 작성 후 action_items.md에 기록",
      "due": "2026-05-15 12:00 KST",
      "status": "확정",
      "source_certainty": "높음"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로 확인",
      "due": "미정(결과 공유 이후)",
      "status": "조건부",
      "source_certainty": "높음"
    },
    {
      "owner": "미정",
      "task": "README 설치 단계 최신성 검토",
      "due": "가능하면 2026-05-14(목)까지(권고)",
      "status": "미확정",
      "source_certainty": "중간"
    },
    {
      "owner": "미정",
      "task": "최종 릴리스 승인 권한자(Owner) 확인",
      "due": "다음 회의 전",
      "status": "열린 질문",
      "source_certainty": "낮음"
    },
    {
      "owner": "미정",
      "task": "릴리스 노트에 내부 스트레치 목표(수요일) 언급 여부 결정",
      "due": "다음 확인 단계",
      "status": "열린 질문",
      "source_certainty": "낮음"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "스모크 테스트 재실행 결과를 기준으로 Friday 15:00 KST 공개 릴리스 가능 여부를 최종 판정한다.",
      "packageName 불일치 사례의 실제 원인이 패키지 설정인지 스크립트 동작인지 증빙(설정 값, 로그, 테스트 출력)을 확인한다.",
      "Hara가 확인한 tarball 경로가 실제 배포/패키징 경로와 일치하는지 즉시 교차 검증한다.",
      "README 설치 단계가 최신인지 확인하고, 필요시 문구/명령어·버전 정보의 정확성을 보완한다.",
      "최종 승인 권한자와 릴리스 노트에 스트레치 목표 언급 여부를 명시적으로 확정한다."
    ],
    "what_not_to_invent": [
      "고객명, 파트너명, 예산, 보안 사고, 운영 장애, 법무 승인, 특정 소유자/데드라인은 주어진 기록에 없는 항목이므로 추가로 추론해 쓰지 않는다.",
      "특정 날짜/시간은 '금요일 10:00/12:00/15:00 KST', '목요일(가능하면)'처럼 명시된 범위 외의 값으로 임의 확정하지 않는다.",
      "제안이 반려되었거나 미확정인 항목(수요일 공개 릴리스, packageName 무시 처리)은 최종 결정으로 바꾸어 기록하지 않는다."
    ]
  },
  "non_invention_rules": [
    "주어진 RAW 노트에 없는 항목은 생성하지 않는다.",
    "고객/예산/보안/장애/법무/소유자/마감일 등의 외부 사실은 모두 미기재면 '미정' 또는 '미확인'으로만 처리한다.",
    "확정된 것(confirmed), 반려된 것(rejected), 내부 스트레치, 리스크, 오픈 질문을 혼동하지 않고 분리해 기술한다.",
    "액션 아이템의 due는 원문 표현(예: '목요일이면 좋음', '결과 공유 후')을 유지하되 임의 날짜 추정을 하지 않는다.",
    "요약은 fixture 내부 근거를 우선해 작성하고, 보조 가정이 필요하면 followup_note의 'what_not_to_invent'로 경고한다."
  ]
}
